import { Plus, Trash2, Square, Play, Monitor } from "lucide-react";

interface Project {
  id: string;
  name: string;
  command: string;
  args: string[];
}

interface ProcessState {
  type: "Stopped" | "Setup" | "Running" | "Crashing" | "Terminated" | "Fatal";
  data?: any;
}

interface ResourceHistory {
  [projectId: string]: {
    cpu: number[];
    ram: number[];
  };
}

interface TabListProps {
  filteredProjects: Project[];
  activeProjectId: string;
  setActiveProjectId: (id: string) => void;
  projectStates: { [id: string]: ProcessState };
  resourceHistory: ResourceHistory;
  setAutoScroll: (b: boolean) => void;
  handleStopProject: (id: string) => void;
  handleStartProject: (id: string) => void;
  handleDeleteProject: (id: string) => void;
  setNewProjName: (v: string) => void;
  setNewProjCmd: (v: string) => void;
  setNewProjArgs: (v: string) => void;
  setNewProjRestart: (v: boolean) => void;
}

export default function TabList({
  filteredProjects,
  activeProjectId,
  setActiveProjectId,
  projectStates,
  resourceHistory,
  setAutoScroll,
  handleStopProject,
  handleStartProject,
  handleDeleteProject,
  setNewProjName,
  setNewProjCmd,
  setNewProjArgs,
  setNewProjRestart
}: TabListProps) {
  return (
    <div className="lower-panel-tab">
      <div className="panel-header-row">
        <h3>Registered Project Tabs ({filteredProjects.length})</h3>
        <button
          className="btn btn-primary btn-sm"
          onClick={() => {
            // Populate default mockup setup
            setNewProjName("Diagnostics Server");
            setNewProjCmd("ping");
            setNewProjArgs("127.0.0.1 -n 100");
            setNewProjRestart(true);
          }}
        >
          <Plus size={13} />
          <span>Fill Boilerplate</span>
        </button>
      </div>

      <div className="tabs-grid-container">
        {filteredProjects.length === 0 ? (
          <div className="no-projects-fallback">
            <Monitor size={32} />
            <p>No tabs registered. Define commands in the yellow panel to begin execution.</p>
          </div>
        ) : (
          filteredProjects.map((p) => {
            const state = projectStates[p.id] || { type: "Stopped" };
            const isActive = p.id === activeProjectId;
            const history = resourceHistory[p.id];
            const currentCpu = history && history.cpu.length > 0 ? history.cpu[history.cpu.length - 1] : 0;
            const currentRam = history && history.ram.length > 0 ? history.ram[history.ram.length - 1] : 0;

            return (
              <div
                key={p.id}
                className={`project-card-item ${isActive ? "active" : ""}`}
                onClick={() => {
                  setActiveProjectId(p.id);
                  setAutoScroll(true);
                }}
              >
                <div className="card-top">
                  <div className="name-group">
                    <strong className="card-name">{p.name}</strong>
                    <span className="card-cmd-preview">
                      $ {p.command} {p.args.join(" ")}
                    </span>
                  </div>
                  <div className={`status-badge status-${state.type.toLowerCase()}`}>
                    <span className="status-dot"></span>
                    <span>{state.type}</span>
                  </div>
                </div>

                <div className="card-body-metrics">
                  {state.type === "Running" && history ? (
                    <div className="quick-stats">
                      <span>CPU: {currentCpu.toFixed(1)}%</span>
                      <span>|</span>
                      <span>RAM: {currentRam.toFixed(1)} MB</span>
                    </div>
                  ) : (
                    <span className="text-muted">Process Idle</span>
                  )}
                </div>

                <div className="card-actions-footer" onClick={(e) => e.stopPropagation()}>
                  <div className="left-btn">
                    {state.type === "Running" || state.type === "Setup" ? (
                      <button
                        className="btn btn-danger btn-xs"
                        onClick={() => {
                          setActiveProjectId(p.id);
                          handleStopProject(p.id);
                        }}
                      >
                        <Square size={9} fill="currentColor" /> Stop
                      </button>
                    ) : (
                      <button
                        className="btn btn-primary btn-xs"
                        onClick={() => {
                          setActiveProjectId(p.id);
                          handleStartProject(p.id);
                        }}
                      >
                        <Play size={9} fill="currentColor" /> Run
                      </button>
                    )}
                  </div>
                  <button
                    className="btn btn-secondary btn-xs text-danger"
                    onClick={() => handleDeleteProject(p.id)}
                  >
                    <Trash2 size={9} /> Delete
                  </button>
                </div>
              </div>
            );
          })
        )}
      </div>
    </div>
  );
}
